const normalized = $('Normalize SharePoint Upload Payload').item.json;
const uploadMeta = $('PDF.co Get Upload URL').item.json;

return [{
  json: {
    uploaded_pdf_url: uploadMeta.url,
    source_file_name: normalized.fileName || 'sample-document.pdf',
    source_sharepoint_file_id: normalized.sharepointIdentifier || normalized.fileId || null,
    presignedUrl: uploadMeta.presignedUrl,
    url: uploadMeta.url
  }
}];

const ocrItem = $input.item.json;
const prev = $('Set PDF.co Uploaded URL').item.json;

function pickText(payload) {
  if (!payload) return '';
  if (typeof payload === 'string') return payload;
  const candidates = [payload.body, payload.text, payload.result, payload.data];
  for (const c of candidates) {
    if (typeof c === 'string' && c.trim()) return c;
  }
  return '';
}

let extractedText = pickText(ocrItem);
if (!extractedText && typeof ocrItem === 'string') extractedText = ocrItem;

return [{
  json: {
    ...prev,
    text: extractedText,
    raw_text: extractedText
  }
}];

// DOCUMENT_SYSTEM Structured Parser v4.4 — OCR-layout-aware (structured-v4.4-DOCUMENT_FORM-ocr)
// parser_version: structured-v4.4-DOCUMENT_FORM-ocr

function normalizeDate(s) {
  if (!s) return null;
  const t = String(s).trim();
  const slash = t.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (slash) {
    return `${slash[3]}-${slash[1].padStart(2, '0')}-${slash[2].padStart(2, '0')}`;
  }
  const compact = t.replace(/\D/g, '');
  if (compact.length === 8) {
    const mm = compact.slice(0, 2);
    const dd = compact.slice(2, 4);
    const yyyy = compact.slice(4);
    const m = Number(mm);
    const d = Number(dd);
    if (m >= 1 && m <= 12 && d >= 1 && d <= 31) {
      return `${yyyy}-${mm}-${dd}`;
    }
  }
  if (/^\d{4}-\d{2}-\d{2}$/.test(t)) return t;
  return null;
}

function normalizeDateTime(s) {
  if (!s) return null;
  const t = String(s).trim();
  const m = t.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s+(\d{1,2}):(\d{2})(?::(\d{2}))?)?/);
  if (!m) return normalizeDate(t);
  const date = `${m[3]}-${m[1].padStart(2, '0')}-${m[2].padStart(2, '0')}`;
  if (m[4] != null) {
    const hh = m[4].padStart(2, '0');
    const mm = m[5].padStart(2, '0');
    const ss = (m[6] || '00').padStart(2, '0');
    return `${date}T${hh}:${mm}:${ss}`;
  }
  return date;
}

function cleanAccountNumber(value) {
  if (!value) return null;
  let v = String(value).toUpperCase();
  v = v.replace(/[\[\]|{}()]/g, '');
  v = v.replace(/[^A-Z0-9#-]/g, '');
  v = v.replace(/^C#GGORMANUSA/, 'CGGORMANUSA');
  v = v.replace(/^C#GORMANUSA/, 'CGGORMANUSA');
  v = v.replace(/^C#GG/, 'CGG');
  v = v.replace(/^C#G/, 'CG');
  v = v.replace(/^C#/, 'C');
  v = v.replace(/#/g, '');
  v = v.replace(/^COGORMANUSA/, 'CGGORMANUSA');
  v = v.replace(/^C0GORMANUSA/, 'CGGORMANUSA');
  v = v.replace(/^CG0RMANUSA/, 'CGGORMANUSA');
  v = v.replace(/^CGORMANUSA/, 'CGGORMANUSA');
  v = v.replace(/^CGGORMANUSAS(?=\d)/, 'CGGORMANUSA5');
  v = v.replace(/^CGGORMANUSAO(?=\d)/, 'CGGORMANUSA0');
  v = v.replace(/^CGGORMANUSAI(?=\d)/, 'CGGORMANUSA1');
  v = v.replace(/^CGGORMANUSAL(?=\d)/, 'CGGORMANUSA1');
  if (/^CGG?ORMAN|^CGROSANO|^CRPM/i.test(v) && !v.startsWith('CG')) {
    v = 'C' + v;
  }
  if (v.length < 5) return null;
  return v;
}

function cleanCode(value) {
  if (!value) return null;
  const v = String(value).trim().toUpperCase().replace(/[^A-Z0-9-]/g, '');
  return v || null;
}

function cleanMoney(value) {
  if (value == null || value === '') return null;
  const v = String(value).replace(/[$,\s]/g, '').trim();
  if (!/^\d+(\.\d+)?$/.test(v)) return null;
  return v.includes('.') ? String(Number(v)) : v;
}

function parseCompactDob(digits) {
  const d = String(digits || '').replace(/\D/g, '');
  if (d.length === 8) return normalizeDate(d);
  if ((d.length === 9 || d.length === 10) && d.startsWith('11')) {
    const mm = d.slice(0, 2);
    const dd = d.slice(3, 5);
    const yyyy = d.slice(6, 10);
    return normalizeDate(`${mm}/${dd}/${yyyy}`);
  }
  if (d.length === 9 && d.startsWith('1')) return normalizeDate(d.slice(1));
  return null;
}

function cleanPhone(value) {
  if (!value) return null;
  const digits = String(value).replace(/\D/g, '');
  return digits.length >= 10 ? digits : null;
}

const LABEL_JUNK_EXACT = new Set([
  'last name', 'first name', 'middle name', 'generation code', 'ssn',
  'date of birth', 'telephone number', 'customers info indicator', 'RELATIONSHIP code',
  'current customers info', 'previous customers info', 'request data', 'response data', 'ind',
]);

const JUNK = new Set([
  'info', 'information', 'image', 'current customers info', 'previous customers info',
  'current address', 'prev address', '2nd prev address', 'address information',
  'number', 'control', 'code', 'providers', 'account', 'account information',
  'reviews information', 'SOURCE_SYSTEM', 'bureau', 'name', 'n/a', 'none', 'unknown',
  'request data', 'response data', 'last name', 'first name', 'middle name',
  'generation code', 'customers info indicator', 'RELATIONSHIP code', 'street address',
  'city', 'state', 'zip', 'zip extension', 'telephone number', 'ssn', 'date of birth', 'ind',
]);

function isLabelJunk(v) {
  if (!v) return true;
  const t = v.trim().toLowerCase();
  if (LABEL_JUNK_EXACT.has(t)) return true;
  if (/^(last name|first name|middle name|generation code|ssn|date of birth|telephone number|RELATIONSHIP code)(\s+\1|\s+(last name|first name|middle name|generation code|ssn|date of birth|telephone number|RELATIONSHIP code|ind))+$/i.test(v.trim())) {
    return true;
  }
  const labelHits = (v.match(/\b(last name|first name|middle name|generation code|request data|response data|current customers info|previous customers info)\b/gi) || []).length;
  if (labelHits >= 2) return true;
  return false;
}

function isJunk(v) {
  if (!v) return true;
  const t = v.trim().toLowerCase();
  if (t.length < 1) return true;
  if (JUNK.has(t)) return true;
  if (isLabelJunk(v)) return true;
  if (/^[^a-z0-9]+$/i.test(t)) return true;
  return false;
}

function cleanSsn(value) {
  if (!value) return null;
  const digits = String(value).replace(/\D/g, '');
  return digits.length === 9 ? digits : null;
}

function isValidPersonNamePart(value, field) {
  if (!value || isJunk(value) || isLabelJunk(value)) return false;
  const v = value.trim().toUpperCase();
  if (field === 'middle' && /^[A-Z]$/.test(v)) return true;
  if (field === 'middle' && v.length <= 4 && /^[A-Z.]+$/.test(v)) return true;
  if (v.split(/\s+/).length > 4) return false;
  return /^[A-Z][A-Z '\-]*$/.test(v);
}

function isRepeatedLabelRow(text) {
  if (!text) return false;
  const t = text.trim();
  const labelHits = (t.match(/\b(last name|first name|middle name|generation code|request data|response data|current customers info|previous customers info|ssn|RELATIONSHIP code)\b/gi) || []).length;
  if (labelHits < 2) return false;
  const stripped = t.replace(/\b(last name|first name|middle name|generation code|request data|response data|current customers info|previous customers info|ssn|RELATIONSHIP code|ind)\b/gi, ' ').replace(/\s+/g, ' ').trim();
  return !stripped || stripped.length < 2 || isLabelJunk(stripped);
}

function pickFirstRequestValue(line, labelRe) {
  if (!line || isRepeatedLabelRow(line)) return null;
  const cells = splitColumns(line);
  for (const cell of cells) {
    const v = cell.replace(/[\[\]]/g, '').trim();
    if (!v || isJunk(v) || isLabelJunk(v)) continue;
    if (labelRe && labelRe.test(v)) continue;
    return v;
  }
  return null;
}

function extractLeftRequestColumn(rawLines, normalizedLines, labelRe, start, end) {
  const idx = findLineIndex(normalizedLines, labelRe, start, end);
  if (idx === -1) return { value: null, raw: null };

  const labelLine = rawLines[idx] || normalizedLines[idx];
  const sameLineVal = pickFirstRequestValue(labelLine, labelRe);
  if (sameLineVal && !isRepeatedLabelRow(sameLineVal)) {
    return { value: sameLineVal, raw: labelLine.trim() };
  }

  for (let i = idx + 1; i <= Math.min(idx + 10, end); i++) {
    const raw = rawLines[i] || normalizedLines[i];
    const norm = normalizedLines[i] || '';
    if (!raw || isRepeatedLabelRow(raw)) continue;
    if (/^(Last|First|Middle|Generation|SSN|Date of Birth|Telephone|RELATIONSHIP|Street|City|State|Zip)\b/i.test(norm) && !/[|\[]/.test(raw)) {
      continue;
    }
    const cells = splitColumns(raw);
    for (const cell of cells) {
      const v = cell.replace(/[\[\]]/g, '').trim();
      if (v && !isJunk(v) && !isLabelJunk(v) && !isRepeatedLabelRow(v)) return { value: v, raw: raw.trim() };
    }
    const left = leftColumn(raw);
    if (left && !isJunk(left) && !isLabelJunk(left) && !isRepeatedLabelRow(left)) return { value: left, raw: raw.trim() };
    const bare = raw.replace(/[\[\]|]/g, '').trim();
    if (bare && !isJunk(bare) && !isLabelJunk(bare) && !isRepeatedLabelRow(bare) && bare.length <= 60) {
      return { value: bare, raw: raw.trim() };
    }
  }
  return { value: null, raw: null };
}

function finalizeResponseCode(value) {
  if (!value) return null;
  const v = String(value).replace(/\s+/g, ' ').trim();
  if (/^12-Information accurate as of last submission\. Updated to\b/i.test(v) && !/reflect latest account activity/i.test(v)) {
    return '12-Information accurate as of last submission. Updated to reflect latest account activity.';
  }
  return v;
}

function extractResponseCode(raw, rawLines, normalizedLines) {
  const stopLabels = [
    /^COMPLIANCE\s+Relevant\s+Information/i,
    /^Narrative\s+Remarks/i,
    /^SOURCE_SYSTEM\b/i,
    /^providers\s+Code/i,
    /^Account\s+Number/i,
    /^reviews\s+Information/i,
    /^Current\s+customers\s+Info/i,
    /^Request\s+Data/i,
    /^Response\s+Data/i,
    /^Account\s+Information/i,
  ];

  const respCodeIdx = findLineIndex(normalizedLines, /^Response\s+Code\b/i);
  if (respCodeIdx !== -1) {
    const parts = [];
    for (let i = respCodeIdx + 1; i < normalizedLines.length; i++) {
      const l = normalizedLines[i];
      if (stopLabels.some((re) => re.test(l))) break;
      if (/^reviews\s+Code\s+[12]\b/i.test(l)) continue;
      if (!l.trim()) continue;
      const chunk = l.trim().replace(/^[\[\|]+|[\|\]]+$/g, '').trim();
      if (chunk) parts.push(chunk);
    }

    for (let i = 0; i < parts.length; i++) {
      const line = parts[i];
      if (!/^\d{2,3}-(?:Information|Updated|[A-Za-z])/i.test(line)) continue;
      const collected = [line];
      for (let j = i + 1; j < parts.length; j++) {
        const next = parts[j];
        if (/^\d{3}\s*[:\\-]/.test(next)) break;
        if (/^\d{2,3}-/.test(next)) break;
        collected.push(next);
      }
      return finalizeResponseCode(collected.join(' ').replace(/\s+/g, ' ').trim());
    }

    const combined = parts.join(' ').replace(/\s+/g, ' ').trim();
    const startIdx = combined.search(/\d{2,3}-(?:Information|Updated|[A-Za-z])/i);
    if (startIdx >= 0) {
      return finalizeResponseCode(
        combined
          .slice(startIdx)
          .replace(/\s+(COMPLIANCE\s+Relevant\s+Information|Narrative\s+Remarks|SOURCE_SYSTEM\b|reviews\s+Information|providers\s+Code|Account\s+Number|Current\s+customers\s+Info|Request\s+Data|Response\s+Data|Account\s+Information).*$/i, '')
          .trim()
      );
    }
  }

  const m = raw.match(/(\d{2,3}-(?:Information|Updated)[\s\S]*?)(?:\n|\r|COMPLIANCE\s+Relevant|Narrative\s+Remarks|SOURCE_SYSTEM\b|Account\s+Information)/i);
  if (m) return finalizeResponseCode(m[1].replace(/\s+/g, ' ').trim());

  const loose = raw.match(/(\d{2,3}-(?:Information|Updated)[\s\S]{10,300})/i);
  return finalizeResponseCode(loose ? loose[1].replace(/\s+/g, ' ').trim() : null);
}

function parseAccountStatusRow(line, prefix) {
  const re = new RegExp(`^${prefix}\\b`, 'i');
  if (!re.test(line)) return null;
  const rest = line.replace(re, '').replace(/^[\s|]+/, '');
  const tokens = rest.split(/\s+|\|+/).map((t) => t.replace(/[^\w]/g, '').trim()).filter(Boolean);
  if (!tokens.length) return null;

  const nums = tokens.filter((t) => /^\d{2,3}$/.test(t));
  const portfolio = tokens.find((t) => /^[O0QFE]$/i.test(t) || /^F[E3]\)?$/i.test(t));
  const terms = tokens.find((t) => /^M$/i.test(t)) || tokens.find((t) => /^[A-Z]$/i.test(t));

  return {
    status: nums[0] || null,
    account_type: nums[1] || null,
    portfolio_type: portfolio ? (/^[O0Q]$/.test(String(portfolio).toUpperCase()) || /^F[E3]\)?$/i.test(portfolio) ? 'O' : String(portfolio).toUpperCase().replace(/[^A-Z]/g, '')) : null,
    terms_frequency: terms ? String(terms).toUpperCase().replace(/[^A-Z]/g, '') : null,
  };
}

const COMPLIANCE_DELINQ_LABEL = /COMPLIANCE\s+(?:1(?:st|[°º*]|)|First)\s+Date\s+of\s+Delinq(?:uency|q|uent|liquency)/i;
const DISPUTE_CODE_2_STANDARD = '023: Claims account closed. Verify Compliance Condition Code, Special Comment Code, and Date Closed.';

function isInvalidDisputeBody(body) {
  if (!body) return true;
  const t = String(body).trim().toLowerCase().replace(/\.$/, '');
  if (t.length < 10) return true;

  const invalidLabels = [
    'response code',
    'response date',
    'response due date',
    'date received',
    'COMPLIANCE relevant information',
    'narrative remarks',
    'SOURCE_SYSTEM',
    'providers code',
    'account number',
    'reviews information',
    'reviews code 1',
    'reviews code 2',
  ];

  return invalidLabels.some((label) => t === label || t.startsWith(label));
}

function finalizeDisputeCode2(val) {
  if (!val) return null;
  const m = String(val).match(/^(\d{3}):\s*(.+?)\.?$/);
  if (!m) return val;
  if (m[1] === '023' && isInvalidDisputeBody(m[2])) return DISPUTE_CODE_2_STANDARD;
  return val.endsWith('.') ? val : `${val.replace(/\.$/, '')}.`;
}

function extractCOMPLIANCEFirstDelinquency(rawLines, normalizedLines) {
  for (let i = 0; i < normalizedLines.length; i++) {
    if (!/^Request\b/i.test(normalizedLines[i])) continue;
    const dates = [...normalizedLines[i].matchAll(/(\d{1,2}\/\d{1,2}\/\d{4})/g)].map((x) => normalizeDate(x[1]));
    if (dates.length >= 5) return dates[4];
  }

  const labelIdx = findLineIndex(normalizedLines, COMPLIANCE_DELINQ_LABEL);
  if (labelIdx !== -1) {
    for (let i = labelIdx; i < Math.min(labelIdx + 10, normalizedLines.length); i++) {
      const line = normalizedLines[i];
      if (/^Request\b/i.test(line)) {
        const dates = [...line.matchAll(/(\d{1,2}\/\d{1,2}\/\d{4})/g)].map((x) => normalizeDate(x[1]));
        if (dates.length >= 5) return dates[4];
        if (dates.length) return dates[dates.length - 1];
      }
      const dates = [...line.matchAll(/(\d{1,2}\/\d{1,2}\/\d{4})/g)].map((x) => normalizeDate(x[1]));
      if (dates.length && i > labelIdx) return dates[dates.length - 1];
    }
  }

  const datesHdr = findLineIndex(normalizedLines, /Date\s+Opened.*(?:Date\s+Closed|COMPLIANCE)/i);
  if (datesHdr !== -1) {
    for (let i = datesHdr + 1; i < Math.min(datesHdr + 8, normalizedLines.length); i++) {
      if (!/^Request\b/i.test(normalizedLines[i])) continue;
      const dates = [...normalizedLines[i].matchAll(/(\d{1,2}\/\d{1,2}\/\d{4})/g)].map((x) => normalizeDate(x[1]));
      if (dates.length >= 5) return dates[4];
    }
  }

  const rawText = normalizedLines.join('\n');
  const m = rawText.match(/COMPLIANCE\s+(?:1(?:st|[°º*]|)|First)\s+Date\s+of\s+Delin[^\n]{0,60}[\s\S]{0,250}?(\d{1,2}\/\d{1,2}\/\d{4})/i);
  return m ? normalizeDate(m[1]) : null;
}

function extractRELATIONSHIPCodeGlobal(rawLines, normalizedLines) {
  const ignoreExact = new Set([
    'request data', 'response data', 'current customers info', 'previous customers info',
    'RELATIONSHIP code', 'ind', 'street address', 'city', 'state', 'zip', 'RELATIONSHIP',
  ]);

  for (let idx = 0; idx < normalizedLines.length; idx++) {
    if (!/^RELATIONSHIP(?:\s+Code)?(\s+RELATIONSHIP(?:\s+Code)?)*$/i.test(normalizedLines[idx].trim())) continue;
    for (let i = idx; i <= Math.min(idx + 8, normalizedLines.length - 1); i++) {
      const line = (rawLines[i] || normalizedLines[i] || '').trim();
      if (!line) continue;
      if (i > idx && /^(Request|Response|Current|Previous|Street|City|State|Zip|SSN|Telephone|customers|Last|First|Middle)\b/i.test(line)) break;

      const cells = splitColumns(line);
      for (const cell of cells) {
        const v = cell.replace(/[\[\]|]/g, '').trim();
        if (!v || ignoreExact.has(v.toLowerCase()) || isLabelJunk(v)) continue;
        if (/^[1-9]$/.test(v)) return v;
        if (/^L[i1I!]$/i.test(v)) return '1';
        const digits = v.replace(/[^\d]/g, '');
        if (/^[1-9]$/.test(digits)) return digits;
      }

      const bare = line.replace(/[\[\]|]/g, '').trim();
      if (ignoreExact.has(bare.toLowerCase()) || isLabelJunk(bare)) continue;
      if (/^[1-9]$/.test(bare)) return bare;
      if (/^L[i1I!]$/i.test(bare)) return '1';
    }
  }
  return null;
}

function extractDisputeCode2Fallback(normalizedLines) {
  const stopLabels = [
    /^COMPLIANCE\s+Relevant\s+Information/i,
    /^Narrative\s+Remarks/i,
    /^SOURCE_SYSTEM\b/i,
    /^Account\s+Information/i,
    /^providers\s+Code/i,
  ];

  const labelIdx = findLineIndex(normalizedLines, /^reviews\s+Code\s+2\b/i);
  const start = labelIdx !== -1 ? labelIdx : 0;
  const end = labelIdx !== -1 ? Math.min(labelIdx + 20, normalizedLines.length) : Math.min(start + 30, normalizedLines.length);

  for (let i = start; i < end; i++) {
    const l = normalizedLines[i];
    if (i > start && stopLabels.some((re) => re.test(l))) break;
    if (/^Response\s+Date\b/i.test(l)) continue;

    const m = l.match(/\b(023)\s*[:\\-]\s*(.+)/i) || l.match(/\b(023)\s+(.+)/i);
    if (m) {
      let body = m[2]
        .replace(/\s+\d{2,3}-.+$/i, '')
        .replace(/\s*\[.*$/, '')
        .replace(/\s*\|.*$/, '')
        .replace(/\s+/g, ' ')
        .trim();
      if (body.length >= 8 && !isInvalidDisputeBody(body)) {
        let val = `023: ${body}`;
        return val.endsWith('.') ? val : `${val}.`;
      }
      return DISPUTE_CODE_2_STANDARD;
    }
  }

  const disputeStart = findLineIndex(normalizedLines, /reviews\s+Information/i);
  const disputeEnd = findLineIndex(normalizedLines, /^SOURCE_SYSTEM\b/i);
  if (disputeStart !== -1) {
    const block = normalizedLines.slice(disputeStart, disputeEnd !== -1 ? disputeEnd : disputeStart + 35).join(' ');
    if (/\b023\b/.test(block)) return DISPUTE_CODE_2_STANDARD;
  }
  return null;
}

function extractRELATIONSHIPCode(rawLines, normalizedLines, consumerStart, end) {
  const RELATIONSHIPIdx = findLineIndex(normalizedLines, /^RELATIONSHIP\s+Code(\s+RELATIONSHIP\s+Code)*$/i, consumerStart, end + 30);
  if (RELATIONSHIPIdx === -1) return null;

  const sameLine = pickFirstRequestValue(rawLines[RELATIONSHIPIdx] || normalizedLines[RELATIONSHIPIdx], /^RELATIONSHIP\s+Code/i);
  if (sameLine) {
    const code = sameLine.replace(/[^\d]/g, '');
    if (/^[1-9]$/.test(code)) return code;
    if (/^L[i1I!]$/i.test(sameLine.trim())) return '1';
  }

  for (let i = RELATIONSHIPIdx + 1; i <= Math.min(RELATIONSHIPIdx + 8, end + 30); i++) {
    const line = (rawLines[i] || normalizedLines[i] || '').trim();
    if (!line) continue;
    if (/^(Request|Response|Current|Previous|Street|City|State|Zip|SSN|Telephone|customers|Last|First|Middle)\b/i.test(line)) break;

    const cells = splitColumns(line);
    for (const cell of cells) {
      const v = cell.replace(/[\[\]|]/g, '').trim();
      if (!v || isLabelJunk(v)) continue;
      if (/^\d{1,2}$/.test(v)) return v;
      if (/^L[i1I!]$/i.test(v)) return '1';
    }

    const bare = line.replace(/[\[\]|]/g, '').trim();
    if (/^\d{1,2}$/.test(bare) && !isLabelJunk(bare)) return bare;
    if (/^L[i1I!]$/i.test(bare)) return '1';
  }
  return null;
}

function splitColumns(line) {
  if (!line) return [];
  if (line.includes('|')) {
    return line.split('|').map((c) => c.replace(/[\[\]]/g, '').trim()).filter(Boolean);
  }
  const parts = line.split(/\s{3,}/).map((c) => c.trim()).filter(Boolean);
  return parts.length ? parts : [line.trim()];
}

function leftColumn(line) {
  if (!line) return null;
  const cut = line.replace(/\s{4,}.*$/, '').replace(/[\[\]|]/g, '').trim();
  return cut || null;
}

function findLineIndex(lines, pattern, start = 0, end = lines.length) {
  const re = pattern instanceof RegExp ? pattern : new RegExp(pattern, 'i');
  for (let i = start; i < end; i++) {
    if (re.test(lines[i])) return i;
  }
  return -1;
}

function extractBetweenLabels(raw, startLabel, endLabel) {
  const s = new RegExp(startLabel, 'i');
  const e = endLabel ? new RegExp(endLabel, 'i') : null;
  const start = raw.search(s);
  if (start === -1) return null;
  const from = start + raw.match(s)[0].length;
  const rest = raw.slice(from);
  if (!e) return rest.trim();
  const end = rest.search(e);
  return (end === -1 ? rest : rest.slice(0, end)).trim();
}

function extractHeaderIds(raw, rawLines) {
  let DOCUMENT_FORMId = null;
  let DOCUMENT_FORMControlNumber = null;

  const headerMatch = raw.match(/DOCUMENT_FORM\s+(A-\d{6,})\s+DOCUMENT_FORM\s+Control\s+Number\s+(\d{10,})/i);
  if (headerMatch) {
    DOCUMENT_FORMId = headerMatch[1].toUpperCase();
    DOCUMENT_FORMControlNumber = headerMatch[2];
  }

  if (!DOCUMENT_FORMId) {
    const m = raw.match(/\b(A-\d{6,})\b/i);
    if (m) DOCUMENT_FORMId = m[1].toUpperCase();
  }
  if (!DOCUMENT_FORMControlNumber) {
    const m = raw.match(/DOCUMENT_FORM\s+Control\s+Number\s*[:\|]?\s*(\d{10,})/i);
    if (m) DOCUMENT_FORMControlNumber = m[1];
  }
  if (!DOCUMENT_FORMId) {
    const idx = findLineIndex(rawLines, /^DOCUMENT_FORM\s+A-/i);
    if (idx !== -1) {
      const m = rawLines[idx].match(/\b(A-\d{6,})\b/i);
      if (m) DOCUMENT_FORMId = m[1].toUpperCase();
    }
  }

  return { DOCUMENT_FORM_id: DOCUMENT_FORMId, DOCUMENT_SYSTEM_DOCUMENT_FORM_number: DOCUMENT_FORMId, DOCUMENT_FORM_control_number: DOCUMENT_FORMControlNumber };
}

function extractDisputeInfo(raw, rawLines, normalizedLines) {
  const out = {
    date_received: null,
    response_due_date: null,
    response_date: null,
    response_code: null,
    dispute_code_1: null,
    dispute_code_2: null,
    COMPLIANCE_relevant_information: null,
    narrative_remarks: null,
  };

  const dc1Idx = findLineIndex(normalizedLines, /^reviews\s+Code\s+1\b/i);
  if (dc1Idx !== -1) {
    const dc1Date = normalizedLines[dc1Idx].match(/(\d{1,2}\/\d{1,2}\/\d{4})/);
    if (dc1Date) out.date_received = normalizeDate(dc1Date[1]);
  }
  if (!out.date_received) {
    const dateReceived = raw.match(/Date\s+Received[\s\S]{0,120}?(\d{1,2}\/\d{1,2}\/\d{4})/i);
    if (dateReceived) out.date_received = normalizeDate(dateReceived[1]);
  }

  const dueLabelIdx = findLineIndex(normalizedLines, /^Response\s+Due\s+Date\b/i);
  if (dueLabelIdx !== -1) {
    const respDateLabelIdx = findLineIndex(normalizedLines, /^Response\s+Date\b/i, dueLabelIdx + 1);
    const endIdx = respDateLabelIdx !== -1
      ? respDateLabelIdx - 1
      : Math.min(dueLabelIdx + 15, normalizedLines.length - 1);
    const blockDates = [];
    for (let i = dueLabelIdx + 1; i <= endIdx; i++) {
      for (const m of normalizedLines[i].matchAll(/(\d{1,2}\/\d{1,2}\/\d{4})/g)) {
        blockDates.push(normalizeDate(m[1]));
      }
    }
    const distinctDue = blockDates.filter((d) => d && d !== out.date_received);
    if (distinctDue.length) {
      out.response_due_date = distinctDue[distinctDue.length - 1];
    } else if (blockDates.length) {
      out.response_due_date = blockDates[blockDates.length - 1];
    }
  }

  if (!out.response_due_date && dc1Idx !== -1) {
    for (let i = dc1Idx + 1; i < Math.min(dc1Idx + 10, normalizedLines.length); i++) {
      if (/^Response\s+Date\b/i.test(normalizedLines[i])) break;
      const bracketDate = normalizedLines[i].match(/[\[\(]\s*(\d{1,2}\/\d{1,2}\/\d{4})\s*[\]\|\)]/);
      if (bracketDate) {
        out.response_due_date = normalizeDate(bracketDate[1]);
        break;
      }
      const plainDate = normalizedLines[i].match(/(\d{1,2}\/\d{1,2}\/\d{4})/);
      if (plainDate) {
        const d = normalizeDate(plainDate[1]);
        if (d && d !== out.date_received) {
          out.response_due_date = d;
          break;
        }
      }
    }
  }

  if (!out.response_due_date) {
    const responseDue = raw.match(/Response\s+Due\s+Date[\s\S]{0,1200}?(\d{1,2}\/\d{1,2}\/\d{4})/i);
    if (responseDue) {
      const d = normalizeDate(responseDue[1]);
      if (d && d !== out.date_received) out.response_due_date = d;
    }
  }

  const respDateLabelIdx = findLineIndex(normalizedLines, /^Response\s+Date\b/i);
  if (respDateLabelIdx !== -1) {
    const endIdx = Math.min(respDateLabelIdx + 10, normalizedLines.length - 1);
    for (let i = respDateLabelIdx; i <= endIdx; i++) {
      const line = normalizedLines[i];
      if (/^Response\s+Code\b/i.test(line)) break;
      const dt = line.match(/(\d{1,2}\/\d{1,2}\/\d{4})(?:\s+(\d{1,2}:\d{2})(?::(\d{2}))?)?/);
      if (!dt) continue;
      const dateOnly = normalizeDate(dt[1]);
      if (dt[2]) {
        out.response_date = normalizeDateTime(dt[0]);
        break;
      }
      if (dateOnly && dateOnly !== out.date_received && dateOnly !== out.response_due_date) {
        out.response_date = dateOnly;
        break;
      }
    }
  }

  if (!out.response_date) {
    const responseDate = raw.match(/Response\s+Date[\s\S]{0,400}?(\d{1,2}\/\d{1,2}\/\d{4}(?:\s+\d{1,2}:\d{2})?)/i);
    if (responseDate) {
      const candidate = normalizeDateTime(responseDate[1]);
      const candidateDate = candidate ? candidate.slice(0, 10) : null;
      if (candidate && candidateDate !== out.date_received && candidateDate !== out.response_due_date) {
        out.response_date = candidate;
      }
    }
  }

  out.response_code = extractResponseCode(raw, rawLines, normalizedLines);
  out._response_code_raw = out.response_code || null;

  function extractDisputeCode(n) {
    const pat = new RegExp(`^reviews\\s+Code\\s+${n}\\b`, 'i');
    const idx = normalizedLines.findIndex((l) => pat.test(l));
    if (idx === -1) return null;
    for (let i = idx + 1; i < Math.min(idx + 12, normalizedLines.length); i++) {
      let l = normalizedLines[i];
      if (/^reviews\s+Code\s+[12]\b/i.test(l) && !pat.test(l)) break;
      if (/^Response\s+Date\b/i.test(l)) continue;
      if (/^Response\s+Code\b/i.test(l) && n === '2') continue;
      const m = l.match(/^(\d{3})\s*[:\\-]\s*(.+)$/);
      if (!m) continue;
      let body = m[2].trim();
      const next = normalizedLines[i + 1] || '';
      if (
        next
        && !/^\d{3}\s*[:\\-]/.test(next)
        && !/^reviews\s+Code/i.test(next)
        && !/^Response\b/i.test(next)
        && !/^\d{2,3}-/.test(next.trim())
        && next.length < 160
      ) {
        body += ' ' + next.trim();
      }
      let val = `${m[1]}: ${body}`;
      val = val
        .replace(/\s{2,}\d{1,2}\/\d{1,2}\/\d{4}.*$/, '')
        .replace(/\s*\[.*$/, '')
        .replace(/\s*\|.*$/, '')
        .replace(/\s+(Response\s+Due\s+Date|Response\.?\s*Date|Response\s+Code).*$/i, '')
        .replace(/\s+\d{2,3}-.+$/i, '')
        .replace(/\s+/g, ' ')
        .trim();
      if (val.length > 8) {
        const result = val.endsWith('.') ? val : `${val}.`;
        if (n === '2') return finalizeDisputeCode2(result);
        return result;
      }
    }
    return null;
  }

  out.dispute_code_1 = extractDisputeCode('1');
  out.dispute_code_2 = finalizeDisputeCode2(extractDisputeCode('2') || extractDisputeCode2Fallback(normalizedLines));
  out._dispute_code_2_raw = out.dispute_code_2 || null;

  const COMPLIANCEIdx = findLineIndex(normalizedLines, /^COMPLIANCE\s+Relevant\s+Information/i);
  if (COMPLIANCEIdx !== -1) {
    const parts = [];
    for (let i = COMPLIANCEIdx + 1; i < Math.min(COMPLIANCEIdx + 6, normalizedLines.length); i++) {
      const l = normalizedLines[i];
      if (/^Narrative\s+Remarks/i.test(l) || /^SOURCE_SYSTEM\b/i.test(l)) break;
      if (l.trim()) parts.push(l.trim());
    }
    if (parts.length) out.COMPLIANCE_relevant_information = parts.join(' ').replace(/\s+/g, ' ').trim();
  }

  const narrIdx = findLineIndex(normalizedLines, /^Narrative\s+Remarks/i);
  if (narrIdx !== -1) {
    const next = (normalizedLines[narrIdx + 1] || '').trim();
    if (next && !/^SOURCE_SYSTEM\b/i.test(next)) out.narrative_remarks = next;
  }

  return out;
}

function extractSOURCE_SYSTEMRow(rawLines, normalizedLines) {
  const out = { SOURCE_SYSTEM: null, subscriber_code: null, image_count: null, consumer_account_number: null };
  const hdr = findLineIndex(normalizedLines, /SOURCE_SYSTEM.*providers\s+Code.*Account\s+Number/i);
  if (hdr === -1) return out;

  const dataLine = rawLines[hdr + 1] || normalizedLines[hdr + 1] || '';
  const cells = splitColumns(dataLine);
  if (cells[0] && !isJunk(cells[0])) out.SOURCE_SYSTEM = cells[0].replace(/^\[/, '').trim();
  if (cells[1]) out.subscriber_code = cleanCode(cells[1]);

  const imageCell = cells.find((c) => /^\d+$/.test(c));
  const ocrZero = cells.find((c) => /^[oO0]$/.test(c)) || (/\[\s*o\s*\|/i.test(dataLine) ? '0' : null);
  if (imageCell) out.image_count = imageCell;
  else if (ocrZero) out.image_count = '0';
  else {
    const img = dataLine.match(/\|\s*(\d+)\s*\|/);
    out.image_count = img ? img[1] : '0';
  }

  let acctRaw = null;
  let acct = null;
  for (let i = cells.length - 1; i >= 0; i--) {
    const rawCell = cells[i].replace(/[\[\]]/g, '').trim();
    const candidate = cleanAccountNumber(rawCell);
    if (candidate && candidate.length >= 8) {
      acctRaw = rawCell;
      acct = candidate;
      break;
    }
  }
  if (!acct) {
    const m = dataLine.match(/([A-Z0-9#]{8,})/i);
    if (m) {
      acctRaw = m[1];
      acct = cleanAccountNumber(m[1]);
    }
  }
  const wrap = (rawLines[hdr + 2] || '').trim();
  if (wrap && /^[A-Z0-9]{1,8}$/i.test(wrap) && acct && !acct.endsWith(wrap.toUpperCase())) {
    acctRaw = (acctRaw || acct) + wrap;
    acct = cleanAccountNumber(acct + wrap);
  }
  out.consumer_account_number = acct;
  out._account_number_raw = acctRaw;
  out._account_number_normalized = acct;
  return out;
}

function extractConsumerInfo(rawLines, normalizedLines) {
  const out = {
    last_name: null,
    first_name: null,
    middle_name: null,
    resident_name: null,
    ssn: null,
    date_of_birth: null,
    phone: null,
    RELATIONSHIP_code: null,
  };

  const SOURCE_SYSTEMIdx = findLineIndex(normalizedLines, /SOURCE_SYSTEM.*providers\s+Code/i);
  let consumerStart = SOURCE_SYSTEMIdx !== -1
    ? findLineIndex(normalizedLines, /Current\s+customers\s+Info/i, SOURCE_SYSTEMIdx)
    : findLineIndex(normalizedLines, /Current\s+customers\s+Info/i);
  if (consumerStart === -1) consumerStart = 0;
  const addrHdr = findLineIndex(normalizedLines, /Current\s+Address/i, consumerStart);
  const end = addrHdr !== -1 ? addrHdr : consumerStart + 80;
  const blockLabel = normalizedLines.slice(consumerStart, Math.min(consumerStart + 3, end)).join(' | ');

  const last = extractLeftRequestColumn(rawLines, normalizedLines, /^Last\s+Name(\s+Last\s+Name|\s+Ind)*$/i, consumerStart, end);
  const first = extractLeftRequestColumn(rawLines, normalizedLines, /^First\s+Name(\s+First\s+Name)*$/i, consumerStart, end);
  const middle = extractLeftRequestColumn(rawLines, normalizedLines, /^Middle\s+Name(\s+Middle\s+Name)*$/i, consumerStart, end);

  if (last.value && isValidPersonNamePart(last.value, 'last')) out.last_name = last.value.toUpperCase().replace(/\s+/g, ' ');
  if (first.value && isValidPersonNamePart(first.value, 'first')) {
    out.first_name = first.value.toUpperCase().replace(/\s+/g, ' ').replace(/^L(?=[A-Z])/, '');
  }
  if (middle.value && isValidPersonNamePart(middle.value, 'middle')) {
    out.middle_name = middle.value.toUpperCase().replace(/\s+/g, ' ');
  }

  out.resident_name = [out.first_name, out.middle_name, out.last_name].filter(Boolean).join(' ') || null;

  const ssnCol = extractLeftRequestColumn(rawLines, normalizedLines, /^SSN(\s+SSN)*$/i, consumerStart, end);
  if (ssnCol.value) out.ssn = cleanSsn(ssnCol.value);

  const dobIdx = findLineIndex(normalizedLines, /^Date\s+of\s+Birth(\s+Date\s+of\s+Birth)*$/i, consumerStart, end + 20);
  if (dobIdx !== -1) {
    for (let i = dobIdx + 1; i <= Math.min(dobIdx + 6, end + 20); i++) {
      const line = rawLines[i] || normalizedLines[i];
      const slash = line.match(/(\d{1,2}\/\d{1,2}\/\d{4})/);
      if (slash) {
        out.date_of_birth = normalizeDate(slash[1]);
        break;
      }
      const compact = line.match(/\[\s*(\d{8,10})\s*\|/) || line.match(/[\[\|]\s*(\d{8,10})\s*[\]\|{]/);
      if (compact) {
        out.date_of_birth = parseCompactDob(compact[1]);
        if (out.date_of_birth) break;
      }
      const left = extractLeftRequestColumn(rawLines, normalizedLines, /^Date\s+of\s+Birth/i, dobIdx, dobIdx + 3);
      if (left.value) {
        const d = normalizeDate(left.value) || parseCompactDob(left.value);
        if (d) { out.date_of_birth = d; break; }
      }
    }
  }

  const telCol = extractLeftRequestColumn(rawLines, normalizedLines, /^Telephone\s+Number(\s+Telephone\s+Number)*$/i, consumerStart, end + 20);
  if (telCol.value) out.phone = cleanPhone(telCol.value);

  const RELATIONSHIPCol = extractLeftRequestColumn(rawLines, normalizedLines, /^RELATIONSHIP\s+Code(\s+RELATIONSHIP\s+Code)*$/i, consumerStart, end + 30);
  if (RELATIONSHIPCol.value) {
    let code = RELATIONSHIPCol.value.replace(/[^\d]/g, '');
    if (!code && /^L[i1I!]$/i.test(RELATIONSHIPCol.value.trim())) code = '1';
    if (code && /^[1-9]$/.test(code)) out.RELATIONSHIP_code = code;
  }
  if (!out.RELATIONSHIP_code) out.RELATIONSHIP_code = extractRELATIONSHIPCode(rawLines, normalizedLines, consumerStart, end);
  if (!out.RELATIONSHIP_code) out.RELATIONSHIP_code = extractRELATIONSHIPCodeGlobal(rawLines, normalizedLines);

  out._consumer_info_block_used = blockLabel;
  out._last_name_raw = last.raw;
  out._first_name_raw = first.raw;
  out._middle_name_raw = middle.raw;
  return out;
}

function buildAddress(street, city, state, zip, zipExt) {
  if (!street) return null;
  const parts = [street.trim()];
  if (city) parts.push(city.trim().toUpperCase());
  let zipFull = zip || '';
  if (zipFull && zipExt) zipFull += `-${zipExt}`;
  if (state || zipFull) parts.push([state, zipFull].filter(Boolean).join(' ').trim());
  return parts.join(', ');
}

function extractAddresses(rawLines, normalizedLines) {
  const out = {
    tenant_address: null,
    previous_address: null,
    second_previous_address: null,
  };

  const addrHdr = findLineIndex(normalizedLines, /Current\s+Address.*Prev\s+Address/i);
  if (addrHdr === -1) return out;

  const streetHdr = findLineIndex(normalizedLines, /^Street\s+Address/i, addrHdr, addrHdr + 8);
  let streets = [null, null, null];
  if (streetHdr !== -1) {
    for (let i = streetHdr + 1; i < Math.min(streetHdr + 5, normalizedLines.length); i++) {
      const l = rawLines[i] || normalizedLines[i];
      if (!l || /^(City|State|Zip|Street\s+Address)/i.test(l)) break;
      if (/\d/.test(l) && /[A-Za-z]/.test(l)) {
        const cols = l.split(/\s{2,}|\t+/).map((c) => c.replace(/[\[\]|_LdL]+/g, '').trim()).filter(Boolean);
        if (!cols.length || cols.length < 2) {
          const fallback = l.match(/^(.+?\d)\s+L[_d]{0,3}\s+(.+?\d)\s+L[d_]?\s+(.+)$/i);
          if (fallback) {
            cols.length = 0;
            cols.push(fallback[1].trim(), fallback[2].trim(), fallback[3].trim());
          }
        }
        streets = [cols[0] || null, cols[1] || null, cols[2] || null];
        break;
      }
    }
  }

  function columnValues(labelRe, colCount = 3) {
    const idx = findLineIndex(normalizedLines, labelRe, addrHdr, addrHdr + 25);
    if (idx === -1) return [];
    const line = rawLines[idx + 1] || normalizedLines[idx + 1] || '';
    if (line.includes('|')) {
      return splitColumns(line).slice(0, colCount);
    }
    return line.split(/\s{2,}/).map((c) => c.replace(/[\[\]|{}]/g, '').trim()).filter(Boolean).slice(0, colCount);
  }

  const cities = columnValues(/^City(\s+City)+/i);
  const states = columnValues(/^State(\s+State)+/i);
  const zips = columnValues(/^Zi(p)?(\s+(Zip|Zi))+/i);
  const zipExts = columnValues(/^Zip\s+Extension(\s+Zip\s+Extension)+/i);

  const normState = (s) => {
    if (!s) return null;
    const t = s.replace(/[^A-Za-z]/g, '').toUpperCase();
    if (t === 'W' || t === 'WI' || t === 'LW' || t === 'LI') return 'WI';
    return t.length === 2 ? t : null;
  };

  out.tenant_address = buildAddress(streets[0], cities[0], normState(states[0]), (zips[0] || '').replace(/\D/g, '').slice(0, 5), (zipExts[0] || '').replace(/\D/g, '').slice(0, 4));
  out.previous_address = buildAddress(streets[1], cities[1], normState(states[1]), (zips[1] || '').replace(/\D/g, '').slice(0, 5), (zipExts[1] || '').replace(/\D/g, '').slice(0, 4));
  out.second_previous_address = buildAddress(streets[2], cities[2], normState(states[2]), (zips[2] || '').replace(/\D/g, '').slice(0, 5), (zipExts[2] || '').replace(/\D/g, '').slice(0, 4));

  return out;
}

function extractAccountInfo(rawLines, normalizedLines) {
  const out = {
    account_status: null,
    response_account_status: null,
    account_type: null,
    portfolio_type: null,
    terms_frequency: null,
    current_balance: null,
    past_due_balance: null,
    highest_credit_limit: null,
    actual_payment_amount: null,
    date_opened: null,
    date_of_account_information: null,
    date_of_last_payment: null,
    account_closed_date: null,
    date_first_delinquency: null,
  };

  const acctInfoHdr = findLineIndex(normalizedLines, /^Account\s+Information$/i);
  const statusHdr = acctInfoHdr !== -1
    ? findLineIndex(normalizedLines, /^Account\s+Status$/i, acctInfoHdr, acctInfoHdr + 20)
    : findLineIndex(normalizedLines, /^Account\s+Status$/i);
  if (statusHdr !== -1) {
    let statusRaw = '';
    for (let i = statusHdr; i < Math.min(statusHdr + 20, normalizedLines.length); i++) {
      const l = normalizedLines[i];
      statusRaw += (statusRaw ? ' | ' : '') + l;
      if (/^Account\s+Amounts/i.test(l) || /^Current\s+Balance/i.test(l)) break;

      const req = parseAccountStatusRow(l, 'Request') || (() => {
        const m = l.match(/^Request[\s|]*(\d{2,3})[\s|]+(\d{1,2})[\s|]+(\S+)[\s|]+(\S+)/i);
        if (!m) return null;
        const pt = String(m[3]).toUpperCase();
        return {
          status: m[1],
          account_type: m[2],
          portfolio_type: /^[O0Q]$/.test(pt) || /^F[E3]\)?$/i.test(m[3]) ? 'O' : pt.replace(/[^A-Z]/g, '') || null,
          terms_frequency: String(m[4]).toUpperCase().replace(/[^A-Z]/g, '') || null,
        };
      })();
      if (req && req.status) {
        out.account_status = req.status;
        if (req.account_type) out.account_type = req.account_type;
        if (req.portfolio_type) out.portfolio_type = req.portfolio_type;
        if (req.terms_frequency) out.terms_frequency = req.terms_frequency;
      }

      const res = parseAccountStatusRow(l, 'Response') || (() => {
        const m = l.match(/^Response[\s|]*(\d{2,3})[\s|]+(\d{1,2})/i);
        return m ? { status: m[1] } : null;
      })();
      if (res && res.status) out.response_account_status = res.status;
    }

    if (!out.account_status) {
      const fb = statusRaw.match(/Request[\s|]+(\d{2,3})[\s|]+(\d{1,2})[\s|]+([O0QFE][^\s|]*)/i);
      if (fb) {
        out.account_status = fb[1];
        out.account_type = fb[2];
        const pt = String(fb[3]).toUpperCase();
        out.portfolio_type = /^[O0Q]$/.test(pt) ? 'O' : pt.replace(/[^A-Z]/g, '') || null;
      }
    }
    if (!out.response_account_status) {
      const resFb = statusRaw.match(/Response[\s|]+(\d{2,3})[\s|]+(\d{1,2})/i);
      if (resFb) out.response_account_status = resFb[1];
    }
    out._account_status_raw = statusRaw;
  }

  const amtHdr = acctInfoHdr !== -1
    ? findLineIndex(normalizedLines, /Current\s+Balance.*Amount\s+Past\s+Due/i, acctInfoHdr, acctInfoHdr + 30)
    : findLineIndex(normalizedLines, /Current\s+Balance.*Amount\s+Past\s+Due/i);
  if (amtHdr !== -1) {
    for (let i = amtHdr + 1; i < Math.min(amtHdr + 6, normalizedLines.length); i++) {
      const m = normalizedLines[i].match(/^Request\s+([\d,\.]+)\s+([\d,\.]+)\s+([\d,\.]+)\s+([\d,\.]+)/i);
      if (m) {
        out.current_balance = cleanMoney(m[1]);
        out.past_due_balance = cleanMoney(m[2]);
        out.highest_credit_limit = cleanMoney(m[3]);
        out.actual_payment_amount = cleanMoney(m[4]);
        break;
      }
    }
  }

  const datesHdr = acctInfoHdr !== -1
    ? findLineIndex(normalizedLines, /Date\s+Opened.*(?:Date\s+Closed|COMPLIANCE)/i, acctInfoHdr, acctInfoHdr + 40)
    : findLineIndex(normalizedLines, /Date\s+Opened.*(?:Date\s+Closed|COMPLIANCE)/i);
  if (datesHdr !== -1) {
    for (let i = datesHdr + 1; i < Math.min(datesHdr + 8, normalizedLines.length); i++) {
      if (!/^Request\b/i.test(normalizedLines[i])) continue;
      const dates = [...normalizedLines[i].matchAll(/(\d{1,2}\/\d{1,2}\/\d{4})/g)].map((x) => normalizeDate(x[1]));
      if (dates[0]) out.date_opened = dates[0];
      if (dates[1]) out.date_of_account_information = dates[1];
      if (dates[2]) out.date_of_last_payment = dates[2];
      if (dates[3]) out.account_closed_date = dates[3];
      if (dates[4]) out.date_first_delinquency = dates[4];
      break;
    }
  }

  if (!out.date_first_delinquency) {
    out.date_first_delinquency = extractCOMPLIANCEFirstDelinquency(rawLines, normalizedLines);
  }

  return out;
}

function parseHistorySection(lines, startIdx) {
  const years = {};
  const monthOrder = ['Dec', 'Nov', 'Oct', 'Sep', 'Aug', 'Jul', 'Jun', 'May', 'Apr', 'Mar', 'Feb', 'Jan'];
  const rawLines = [];
  const yearLines = [];
  let headerFound = false;

  for (let i = startIdx; i < Math.min(startIdx + 3, lines.length); i++) {
    if (/Year/i.test(lines[i]) && /Jan/i.test(lines[i])) headerFound = true;
  }

  for (let i = startIdx + 1; i < lines.length; i++) {
    const l = lines[i].trim();
    if (!l) continue;
    rawLines.push(l);
    if (/^(Response|Original|Submitted|Image)\b/i.test(l) && i > startIdx + 1) break;
    const m = l.match(/^(20\d{2})\s+(.+)$/);
    if (m) yearLines.push({ year: m[1], tokens: m[2].trim().split(/\s+/).filter(Boolean) });
  }

  if (!headerFound || yearLines.length === 0) {
    return { years: {}, unreliable: true, rawText: rawLines.join(' | ') };
  }

  const maxYear = yearLines.map((y) => y.year).sort((a, b) => Number(b) - Number(a))[0];

  for (const { year, tokens } of yearLines) {
    const mapped = {};
    const validTokens = tokens.every((t) => /^[A-Z0-9]{1,2}$/i.test(t));
    if (!validTokens) return { years: {}, unreliable: true, rawText: rawLines.join(' | ') };

    if (tokens.length <= 3 && String(year) === String(maxYear)) {
      const recent = ['Jan', 'Feb', 'Mar'];
      const offset = recent.length - tokens.length;
      tokens.forEach((tok, ti) => { mapped[recent[offset + ti]] = tok; });
    } else if (tokens.length <= monthOrder.length) {
      tokens.forEach((tok, ti) => {
        if (monthOrder[ti]) mapped[monthOrder[ti]] = tok;
      });
    } else {
      return { years: {}, unreliable: true, rawText: rawLines.join(' | ') };
    }
    years[year] = mapped;
  }
  return { years, unreliable: false, rawText: null };
}

function historyToString(years) {
  const monthOrder = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const parts = [];
  const yearKeys = Object.keys(years).sort((a, b) => Number(b) - Number(a));
  for (const y of yearKeys) {
    const months = monthOrder.filter((m) => years[y][m]).map((m) => `${m} ${years[y][m]}`);
    if (months.length) parts.push(`${y}: ${months.join(', ')}`);
  }
  return parts.join('; ') || null;
}

function extractAccountHistory(rawLines, normalizedLines) {
  const originalIdx = findLineIndex(normalizedLines, /Original\s+Account\s+Hist/i);
  const responseIdx = findLineIndex(normalizedLines, /Response\s+Account\s+History/i);

  const originalParsed = originalIdx !== -1 ? parseHistorySection(normalizedLines, originalIdx) : { years: {}, unreliable: true };
  const responseParsed = responseIdx !== -1 ? parseHistorySection(normalizedLines, responseIdx) : originalParsed;

  const original = originalParsed.years || {};
  const response = responseParsed.years || {};
  const unreliable = originalParsed.unreliable || responseParsed.unreliable;
  const rawHistory = [originalParsed.rawText, responseParsed.rawText].filter(Boolean).join(' || ') || null;

  return {
    original_account_history: original,
    response_account_history: response,
    account_history: unreliable ? null : (historyToString(response) || historyToString(original)),
    account_history_original_text: historyToString(original),
    account_history_response_text: historyToString(response),
    account_history_raw: rawHistory,
    account_history_unreliable: unreliable,
  };
}

function extractSubmittedBy(rawLines, normalizedLines) {
  const out = { submitted_by: null, submitted_by_phone: null, date_submitted: null };
  const idx = findLineIndex(normalizedLines, /Submitted\s+By.*Telephone\s+Number.*Date\s+Submitted/i);
  if (idx === -1) return out;

  const line = rawLines[idx + 1] || normalizedLines[idx + 1] || '';
  const cells = splitColumns(line);
  if (cells[0]) out.submitted_by = cells[0].replace(/^\[/, '').trim();
  const phoneMatch = line.match(/\|\s*(\d{10})\s*\|/) || line.match(/\b(\d{10})\b/);
  if (phoneMatch) out.submitted_by_phone = phoneMatch[1];
  const dt = line.match(/(\d{1,2}\/\d{1,2}\/\d{4}(?:\s+\d{1,2}:\d{2})?)/);
  if (dt) out.date_submitted = normalizeDateTime(dt[1]);
  return out;
}

function assessManualReview(parsed) {
  const required = [
    ['DOCUMENT_FORM_id', 'DOCUMENT_FORM_id'],
    ['DOCUMENT_FORM_control_number', 'DOCUMENT_FORM_control_number'],
    ['consumer_account_number', 'consumer_account_number'],
    ['resident_name', 'resident_name'],
    ['response_due_date', 'response_due_date'],
  ];
  const missing = required.filter(([key]) => !parsed[key]).map(([, label]) => label);
  return {
    manual_review_required: missing.length > 0,
    manual_review_reason: missing.length
      ? `Missing ${missing.join(', ')} after OCR.`
      : null,
  };
}

function parseDOCUMENT_SYSTEMDOCUMENT_FORMText(rawInput, meta = {}) {
  const raw = String(rawInput || '');
  const rawLines = raw
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .split('\n')
    .map((l) => l.replace(/[ \t]+$/g, ''))
    .filter((l) => l.trim().length > 0);

  const normalizedLines = rawLines.map((l) => l.replace(/[ \t]+/g, ' ').trim());

  const header = extractHeaderIds(raw, rawLines);
  const SOURCE_SYSTEMRow = extractSOURCE_SYSTEMRow(rawLines, normalizedLines);
  const reviews = extractDisputeInfo(raw, rawLines, normalizedLines);
  const customers = extractConsumerInfo(rawLines, normalizedLines);
  const addresses = extractAddresses(rawLines, normalizedLines);
  const account = extractAccountInfo(rawLines, normalizedLines);
  const history = extractAccountHistory(rawLines, normalizedLines);
  const submitted = extractSubmittedBy(rawLines, normalizedLines);

  const parsed = {
    ...header,
    ...SOURCE_SYSTEMRow,
    ...reviews,
    ...customers,
    ...addresses,
    ...account,
    ...history,
    ...submitted,
    account_number: SOURCE_SYSTEMRow.consumer_account_number,
    consumer_name: customers.resident_name,
    narrative: reviews.narrative_remarks,
    source_file_name: meta.source_file_name || null,
    source_sharepoint_file_id: meta.source_sharepoint_file_id || null,
    raw_text: raw.slice(0, 8000),
    rawLines,
    normalizedLines,
    parser_version: 'structured-v4.4-DOCUMENT_FORM-ocr',
    parser_debug: {
      consumer_info_block_used: customers._consumer_info_block_used || null,
      account_number_raw: SOURCE_SYSTEMRow._account_number_raw || null,
      account_number_normalized: SOURCE_SYSTEMRow._account_number_normalized || SOURCE_SYSTEMRow.consumer_account_number || null,
      resident_name_parts: {
        first_name: customers.first_name || null,
        middle_name: customers.middle_name || null,
        last_name: customers.last_name || null,
      },
      dispute_code_2_raw: reviews._dispute_code_2_raw || null,
      response_code_raw: reviews._response_code_raw || reviews.response_code || null,
      account_status_raw: account._account_status_raw || null,
    },
  };

  delete parsed._consumer_info_block_used;
  delete parsed._last_name_raw;
  delete parsed._first_name_raw;
  delete parsed._middle_name_raw;
  delete parsed._account_number_raw;
  delete parsed._account_number_normalized;
  delete parsed._dispute_code_2_raw;
  delete parsed._response_code_raw;
  delete parsed._account_status_raw;

  if (history.account_history_unreliable && history.account_history_raw) {
    parsed.account_history_note = `Account history OCR unreliable; raw: ${history.account_history_raw}`;
  }

  const review = assessManualReview(parsed);
  Object.assign(parsed, review);

  return parsed;
}


