}

function buildFieldContext() {
  const available = new Set(['Subject', 'Status', 'Origin', 'Priority', 'Description', 'AccountId']);
  const describeFields = [];
  let source = 'confirmed_fallback';

  try {
    const describe = $('Describe Salesforce Case Fields').item.json;
    if (describe && Array.isArray(describe.fields)) {
      source = 'describe';
      for (const field of describe.fields) {
        if (field.createable === false) continue;
        available.add(field.name);
        describeFields.push({
          name: field.name,
          label: String(field.label || '').toLowerCase(),
        });
      }
      return { available, describeFields, source };
    }
  } catch (e) {
    // fall through
  }

  for (const name of CONFIRMED_CASE_FIELDS) available.add(name);
  return { available, describeFields, source };
}

function resolveSalesforceFields(parserKey, config, available, describeFields) {
  const { apiNames, labelIncludes, allowMultipleMatches } = config;
  const matches = [];
  const seen = new Set();

  for (const apiName of apiNames) {
    if (!available.has(apiName) || seen.has(apiName)) continue;
    matches.push(apiName);
    seen.add(apiName);
    if (!allowMultipleMatches) return matches;
  }

  for (const field of describeFields) {
    if (!available.has(field.name) || seen.has(field.name)) continue;
    if (!labelIncludes.some((needle) => field.label.includes(needle))) continue;
    matches.push(field.name);
    seen.add(field.name);
    if (!allowMultipleMatches) return matches;
  }

  return matches;
}

