const fileName = pick(body, 'fileName', 'file_name', 'Name', 'name', 'FilenameWithExtension', 'FileNameWithExtension', 'DisplayName', 'displayName');
const webUrl = pick(body, 'webUrl', 'web_url', 'WebUrl', 'Link', 'link', 'Path', 'path');
const siteId = pick(body, 'siteId', 'site_id') || 'SAMPLE_CHANNEL_ID';
const parentFolderId = pick(body, 'parentFolderId', 'parent_folder_id', 'parentId', 'parent_id') || 'SAMPLE_CHANNEL_ID';
const driveId = pick(body, 'driveId', 'drive_id');

if (!sharepointIdentifier) {
  return [{
    json: {
      ok: false,
      action: 'skipped',
      reason: 'missing_file_id',
      message: 'Missing SharePoint identifier in webhook payload.',
      source_file_name: fileName,
      source_sharepoint_file_id: null,
      _stop: true
    }
  }];
}

const nameLower = String(fileName || '').toLowerCase();
if (!nameLower.endsWith('.pdf')) {
  return [{
    json: {
      ok: true,
      action: 'skipped',
      reason: 'non_pdf',
      message: 'File is not a PDF; processing skipped.',
      source_file_name: fileName,
      source_sharepoint_file_id: sharepointIdentifier,
      _stop: true
    }
  }];
}

return [{
  json: {
    sharepointIdentifier,
    fileName: fileName || 'sample-document.pdf',
    siteId,
    driveId,
    parentFolderId,
    webUrl,
    fileId: sharepointIdentifier,
    _stop: false
  }
}];

function esc(value) {
  return String(value).replace(/'/g, "\\'");
}

const item = $input.item.json;
const sharepointId = item.sharepointIdentifier || item.fileId;
const soql = `SELECT Id, CaseNumber, Last_Processed_File_Id__c FROM Case WHERE Last_Processed_File_Id__c = '${esc(sharepointId)}' ORDER BY CreatedDate DESC LIMIT 1`;

return [{ json: { ...item, file_idempotency_soql: soql } }];

const normalized = $('Normalize SharePoint Upload Payload').item.json;
const sf = $input.item.json;
const existing = (sf.records && sf.records[0]) || {};

return [{
  json: {
    ok: true,
    action: 'already_processed',
    reason: 'SharePoint file ID already has a Salesforce Case.',
    source_file_name: normalized.fileName,
    source_sharepoint_file_id: normalized.sharepointIdentifier || normalized.fileId,
    salesforce_case_id: existing.Id || null,
    duplicate_case_number: existing.CaseNumber || null
  }
}];

const normalized = $('Normalize SharePoint Upload Payload').item.json;
const created = $('Create Salesforce Case REST').item.json;
const sfFile = $('Upload DOCUMENT_SYSTEM PDF to Salesforce Case').item.json;
const contentVersion = $('Get Uploaded Salesforce ContentVersion').item.json.records?.[0] || {};

function getNodeJson(name) {
  try {
    return $(name).item.json;
  } catch (e) {
    return null;
  }
}

const sourceDelete = getNodeJson('PDF.co Delete Uploaded Source File');
const ocrDelete = getNodeJson('PDF.co Delete OCR Output File');
const ocrCleanupBody = getNodeJson('Build PDF.co Cleanup Body - OCR Output');

function deleteOk(result) {
  if (!result) return null;
  if (result.error === false) return true;
  if (String(result.status || '') === '200') return true;
  if (result.error) return false;
  return null;
}

return [{
  json: {
    ok: true,
    action: 'created',
    source_file_name: normalized.fileName,
    source_sharepoint_file_id: normalized.sharepointIdentifier || normalized.fileId,
    salesforce_case_id: created.id || created.Id || null,
    salesforce_file_content_version_id: sfFile.id || sfFile.Id || null,
    salesforce_file_content_document_id: contentVersion.ContentDocumentId || null,
    salesforce_file_link_verified: Boolean(contentVersion.ContentDocumentId),
    salesforce_file_should_show_under_case_files: Boolean(contentVersion.ContentDocumentId),
    salesforce_file_uploaded: Boolean(sfFile.id || sfFile.Id),
    pdfco_cleanup: {
      uploaded_source_delete_attempted: true,
      uploaded_source_delete_ok: deleteOk(sourceDelete),
      ocr_output_delete_attempted: Boolean(ocrCleanupBody && ocrCleanupBody.has_pdfco_ocr_output_url),
      ocr_output_delete_ok: deleteOk(ocrDelete)
    }
  }
}];

const stop = $input.item.json;
return [{
  json: {
    ok: true,
    action: 'duplicate',
    source_file_name: stop.source_file_name || null,
    source_sharepoint_file_id: stop.source_sharepoint_file_id || null,
    salesforce_case_id: stop.existing_case_id || null,
    duplicate_case_number: stop.existing_case_number || null,
    reason: stop.message || 'Duplicate Salesforce Case found.'
  }
}];

const parsed = $('Parse DOCUMENT_SYSTEM Fields - Structured').item.json;
const created = $('Create Manual Review Salesforce Case').item.json;
return [{
  json: {
    ok: true,
    action: 'manual_review',
    source_file_name: parsed.source_file_name || null,
    source_sharepoint_file_id: parsed.source_sharepoint_file_id || null,
    salesforce_case_id: created.id || created.Id || null,
    reason: parsed.manual_review_reason || 'Missing required identifiers after OCR.'
  }
}];

const stop = $input.item.json;
return [{
  json: {
    ok: false,
    action: 'error',
    source_file_name: stop.source_file_name || null,
    source_sharepoint_file_id: stop.source_sharepoint_file_id || null,
    reason: stop.reason || 'PDF.co OCR job was not complete.'
  }
}];

const item = $input.item;
const created = item.json || {};
const normalized = $('Normalize SharePoint Upload Payload').item.json;
const sf = $('Set Salesforce Context').item.json;
const pdfcoSource = $('Set PDF.co Uploaded URL').item.json;
const ocrJob = $('PDF.co Check OCR Job').item.json;

const caseId = created.id || created.Id || created.salesforce_case_id;
if (!caseId) {
  throw new Error('Missing Salesforce Case Id from Create Salesforce Case REST. Refusing to upload Salesforce File or delete PDF.co temp file.');
}

if (!item.binary || !item.binary.data) {
  throw new Error('Missing original PDF binary from Download PDF from SharePoint. Check Merge Case With Original PDF input 1.');
}

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
if (!buffer || buffer.length === 0) {
  throw new Error('Original PDF binary buffer is empty. Refusing to upload blank file to Salesforce.');
}

const fileName = normalized.fileName || 'sample-document.pdf';
const title = fileName.replace(/\.pdf$/i, '') || 'DOCUMENT_SYSTEM Document';

return [{
  json: {
    SF_INSTANCE_URL: sf.SF_INSTANCE_URL,
    salesforce_case_id: caseId,
    source_file_name: fileName,
    source_sharepoint_file_id: normalized.sharepointIdentifier || normalized.fileId || null,
    pdfco_uploaded_pdf_url: pdfcoSource.uploaded_pdf_url || pdfcoSource.url || null,
    pdfco_ocr_output_url: ocrJob.url || null,
    content_version_body: {
      Title: title,
      PathOnClient: fileName,
      FirstPublishLocationId: caseId,
      VersionData: buffer.toString('base64')
    }
  }
}];

const source = $('Set PDF.co Uploaded URL').item.json;
const created = $('Create Salesforce Case REST').item.json;
const sfFile = $('Upload DOCUMENT_SYSTEM PDF to Salesforce Case').item.json;

const url = source.uploaded_pdf_url || source.url;
if (!url) {
  throw new Error('Missing PDF.co uploaded PDF URL. Refusing to run cleanup without a target URL.');
}

return [{
  json: {
    url,
    cleanup_target: 'pdfco_uploaded_source_pdf',
    salesforce_case_id: created.id || created.Id || null,
    salesforce_content_version_id: sfFile.id || sfFile.Id || null
  }
}];

const source = $('Set PDF.co Uploaded URL').item.json;
const ocrJob = $('PDF.co Check OCR Job').item.json;
const created = $('Create Salesforce Case REST').item.json;
const sfFile = $('Upload DOCUMENT_SYSTEM PDF to Salesforce Case').item.json;

const uploadedUrl = source.uploaded_pdf_url || source.url || null;
const outputUrl = ocrJob.url || null;

return [{
  json: {
    url: outputUrl,
    has_pdfco_ocr_output_url: Boolean(outputUrl && outputUrl !== uploadedUrl),
    cleanup_target: 'pdfco_ocr_text_output',
    salesforce_case_id: created.id || created.Id || null,
    salesforce_content_version_id: sfFile.id || sfFile.Id || null
  }
}];

function esc(value) {
  return String(value).replace(/'/g, "\\'");
}

const parsed = $('Parse DOCUMENT_SYSTEM Fields - Structured').item.json;
const sf = $('Set Salesforce Context').item.json;
const consumerAccount = parsed.consumer_account_number || parsed.account_number || null;

if (!consumerAccount) {
  return [{
    json: {
      ...parsed,
      SF_INSTANCE_URL: sf.SF_INSTANCE_URL,
      skip_account_lookup: true,
      account_lookup_soql: "SELECT Id, Name, Customer_Account_Number__c FROM Account WHERE Id = '000000000000000AAA'",
      account_lookup_note: 'No consumer_account_number available for Account lookup.'
    }
  }];
}

// Account lookup uses Customer_Account_Number__c (same customers-number field family as Case.Customer_Account_Number__c).
const soql = `SELECT Id, Name, Customer_Account_Number__c FROM Account WHERE Customer_Account_Number__c = '${esc(consumerAccount)}' LIMIT 1`;
return [{
  json: {
    ...parsed,
    SF_INSTANCE_URL: sf.SF_INSTANCE_URL,
    skip_account_lookup: false,
    account_lookup_soql: soql,
    account_lookup_consumer_number: consumerAccount
  }
}];

const check = $input.item.json;
const status = String(check.status || '').toLowerCase().trim();
const url = check.url || check.resultUrl || check.result || null;
const jobId = check.jobId || ($('PDF.co OCR PDF to Text').item.json || {}).jobId || null;

let attempt = 1;
try {
  const retryWait = $('Wait for PDF.co OCR Retry').item.json;
  if (retryWait && retryWait.pdfco_attempt != null) {
    attempt = Number(retryWait.pdfco_attempt) + 1;
  }
} catch (e) {}

const hasUrl = Boolean(url && String(url).trim());
const failedStatuses = new Set(['failed', 'error', 'aborted']);
const processingStatuses = new Set(['working', 'processing', 'pending', 'created', '']);

const pdfco_is_success = status === 'success' && hasUrl;
let pdfco_is_failed = failedStatuses.has(status);
let pdfco_is_still_processing = false;

if (!pdfco_is_success && !pdfco_is_failed && attempt < 5) {
  pdfco_is_still_processing = processingStatuses.has(status) || !failedStatuses.has(status);
}

if (attempt >= 5 && !pdfco_is_success) {
  pdfco_is_failed = true;
  pdfco_is_still_processing = false;
}

return [{
  json: {
    ...check,
    pdfco_job_status: check.status || null,
    pdfco_result_url: hasUrl ? url : null,
    pdfco_job_id: jobId,
    pdfco_attempt: attempt,
    pdfco_is_success,
    pdfco_is_still_processing,
    pdfco_is_failed,
  },
}];
